import React, { useState, useEffect, useCallback } from 'react';
import { endpointsAPI } from '../utils/api';

export default function EndpointsPage({ liveEvents }) {
  const [endpoints, setEndpoints] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [toast, setToast]         = useState('');

  const fetchEndpoints = useCallback(async () => {
    try { const r = await endpointsAPI.list(); setEndpoints(r.data.endpoints); } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { fetchEndpoints(); }, [fetchEndpoints]);
  useEffect(() => { if (liveEvents?.length) fetchEndpoints(); }, [liveEvents, fetchEndpoints]);

  const isolate = async (ep) => {
    const reason = window.prompt(`Reason for isolating ${ep.hostname}?`, 'Suspicious activity');
    if (reason === null) return;
    try { await endpointsAPI.isolate(ep.id, reason); setToast(`${ep.hostname} ISOLATED`); setTimeout(() => setToast(''), 3000); fetchEndpoints(); } catch {}
  };
  const unisolate = async (ep) => {
    try { await endpointsAPI.unisolate(ep.id); setToast(`${ep.hostname} UNISOLATED`); setTimeout(() => setToast(''), 3000); fetchEndpoints(); } catch {}
  };

  const online   = endpoints.filter(e => e.status === 'online' && !e.is_isolated).length;
  const offline  = endpoints.filter(e => e.status !== 'online' && !e.is_isolated).length;
  const isolated = endpoints.filter(e => e.is_isolated).length;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
      {toast && (
        <div className="animate-slide-in-right" style={{ position: 'fixed', top: '20px', right: '20px', zIndex: 200, background: 'rgba(0,212,255,0.1)', border: '1px solid rgba(0,212,255,0.4)', color: 'var(--accent-blue)', fontFamily: "'Space Mono', monospace", fontSize: '10px', letterSpacing: '0.1em', padding: '10px 16px' }}>
          ◈ {toast}
        </div>
      )}

      <div>
        <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.2em', marginBottom: '4px' }}>MODULE // EPT-001</div>
        <h1 style={{ fontSize: '22px', fontWeight: '700', color: 'var(--text-primary)' }}>Endpoint Registry</h1>
      </div>

      {/* Summary cards */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '12px' }}>
        {[
          { label: 'ONLINE', value: online, color: 'var(--accent-green)', dotClass: 'online' },
          { label: 'OFFLINE', value: offline, color: 'var(--text-dim)', dotClass: 'offline' },
          { label: 'ISOLATED', value: isolated, color: 'var(--accent-red)', dotClass: 'alert' },
        ].map(s => (
          <div key={s.label} style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', padding: '16px', position: 'relative' }}>
            <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: `linear-gradient(90deg, ${s.color}60, transparent)` }} />
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '6px' }}>
              <span className={`status-dot ${s.dotClass}`} />
              <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: s.color, letterSpacing: '0.15em' }}>{s.label}</span>
            </div>
            <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '28px', fontWeight: '700', color: s.color }}>{s.value}</div>
          </div>
        ))}
      </div>

      {/* Table */}
      <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: 'linear-gradient(90deg, var(--accent-cyan), transparent)' }} />
        <div style={{ overflowX: 'auto' }}>
          <table className="data-table">
            <thead>
              <tr>
                {['Status', 'Hostname', 'IP Address', 'User', 'Agent', 'Last Seen', 'Action'].map(h => <th key={h}>{h}</th>)}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={7} style={{ textAlign: 'center', padding: '50px', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>SCANNING NETWORK...</td></tr>
              ) : !endpoints.length ? (
                <tr><td colSpan={7} style={{ textAlign: 'center', padding: '50px', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>NO ENDPOINTS REGISTERED — START AGENT ON USER PC</td></tr>
              ) : endpoints.map(ep => (
                <tr key={ep.id}>
                  <td>
                    {ep.is_isolated
                      ? <span style={{ display: 'inline-flex', alignItems: 'center', gap: '5px', fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--accent-red)', background: 'rgba(255,51,102,0.08)', border: '1px solid rgba(255,51,102,0.3)', padding: '3px 8px' }}><span className="status-dot alert" /> ISOLATED</span>
                      : ep.status === 'online'
                        ? <span style={{ display: 'inline-flex', alignItems: 'center', gap: '5px', fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--accent-green)', background: 'rgba(0,255,136,0.06)', border: '1px solid rgba(0,255,136,0.3)', padding: '3px 8px' }}><span className="status-dot online" /> ONLINE</span>
                        : <span style={{ display: 'inline-flex', alignItems: 'center', gap: '5px', fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', background: 'rgba(74,112,144,0.06)', border: '1px solid rgba(74,112,144,0.2)', padding: '3px 8px' }}><span className="status-dot offline" /> OFFLINE</span>
                    }
                  </td>
                  <td style={{ fontWeight: '600', color: 'var(--text-primary)', fontFamily: "'JetBrains Mono', monospace" }}>{ep.hostname}</td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--accent-cyan)' }}>{ep.ip_address || '—'}</td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--text-dim)' }}>{ep.username || '—'}</td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-muted)' }}>v{ep.agent_version}</td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>{ep.last_seen ? new Date(ep.last_seen).toLocaleString() : 'Never'}</td>
                  <td>
                    {ep.is_isolated
                      ? <button className="btn btn-success" style={{ padding: '4px 10px', fontSize: '9px' }} onClick={() => unisolate(ep)}>↺ RESTORE</button>
                      : <button className="btn btn-danger"  style={{ padding: '4px 10px', fontSize: '9px' }} onClick={() => isolate(ep)}>⊗ ISOLATE</button>
                    }
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
